import { GoogleGenAI, Modality } from "@google/genai";
import { GenerationRequest, ProcessedImage } from '../types';

const API_KEY = process.env.API_KEY; // Ensure API Key is loaded from env
const ai = new GoogleGenAI({ apiKey: API_KEY });

export const ensureApiKeySelected = async () => {
  // Hardcoded key used, skipping selection check.
  return;
};

export const generateCompositeImage = async (request: GenerationRequest): Promise<string> => {
  const { personImage, productImage, outfit, pose, backdrop, expression, aspectRatio } = request;

  const backgroundInstruction = backdrop.id === 'original_bg' 
    ? `5. BACKGROUND & ENVIRONMENT:
       CRITICAL: PRESERVE the original background from Image 1. Do not replace the environment.
       The lighting and shadows on the inserted Product (Image 2) must match the existing lighting of Image 1.`
    : `5. BACKGROUND & ENVIRONMENT:
       Replace the original background completely.
       New Setting: ${backdrop.prompt}
       Lighting, shadows, and reflections on the subject and product must realistically match this new setting.`;

  const expressionInstruction = expression.id === 'keep'
    ? 'Maintain the exact facial expression and emotion from Image 1. DO NOT MODIFY THE FACE.'
    : `Modify the facial expression to be: "${expression.prompt}". 
       EXTREMELY IMPORTANT: While changing the expression, you MUST PRESERVE the underlying facial structure and identity of the person in Image 1. The person must be instantly recognizable as the original subject.`;

  const poseInstruction = pose.id === 'context_auto'
    ? `3. POSE & ACTION:
       ANALYZE the context (${backdrop.label}) and the product type.
       GENERATE a natural, realistic pose where the person is interacting with the product in a way that fits the environment.
       Ensure anatomically correct hands.`
    : `3. POSE & ACTION:
       The person holds the Product (Image 2) realistically.
       Pose Style: ${pose.label} - ${pose.desc}.
       Ensure anatomically correct hands and a natural grip.`;

  const promptText = `
    ROLE: Expert Commercial Photographer & Digital Compositor specialized in Product Scale Accuracy.

    INPUTS:
    - Image 1: The Person (Reference for FACE/IDENTITY/BODY SCALE).
    - Image 2: The Product (Reference for OBJECT).

    TASK:
    Generate a highly photorealistic commercial composite image using the person from Image 1 and the product from Image 2.

    TOP PRIORITY - IDENTITY PRESERVATION:
    - The face in the output MUST be the exact same person as in Image 1. 
    - PRESERVE facial features, bone structure, and likeness relative to the angle.
    - DO NOT generate a random face. DO NOT beautify or alter the identity.
    - FAILURE if the person does not look like Image 1.

    CRITICAL CONSTRAINTS:
    1. FACE & EXPRESSION: 
       ${expressionInstruction}
    2. BODY & OUTFIT: 
       ${outfit.id === 'keep' 
         ? 'Keep the original outfit from Image 1.' 
         : `Change the person's outfit to: ${outfit.label} (${outfit.desc}). Fit naturally.`}
    ${poseInstruction}
    4. PRODUCT SCALE & INTEGRATION (EXTREMELY IMPORTANT):
       - ANALYZE the Product in Image 2. ESTIMATE its real-world size (e.g., is it a small lipstick, a medium bottle, or a large bag?).
       - SCALE the product perfectly relative to the Person's hand and body size in Image 1.
       - DO NOT make the product oversized or cartoonishly large. It must look physically accurate.
       - The hand grip must be natural: fingers should wrap around the object realistically based on its estimated thickness.
    ${backgroundInstruction}

    OUTPUT QUALITY: High resolution, commercial photography quality.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { text: promptText },
          { 
            inlineData: { 
              mimeType: personImage.mimeType, 
              data: personImage.base64 
            } 
          },
          { 
            inlineData: { 
              mimeType: productImage.mimeType, 
              data: productImage.base64 
            } 
          }
        ]
      },
      config: {
        responseModalities: ['IMAGE'], // Only want image back
        temperature: 0.4,
        imageConfig: {
          aspectRatio: aspectRatio.id // "1:1", "3:4", "9:16", "16:9", "4:3"
        }
      }
    });

    // Check for inline data (image) in the response parts
    const parts = response.candidates?.[0]?.content?.parts;

    if (parts) {
        for (const part of parts) {
            if (part.inlineData && part.inlineData.data) {
                return `data:image/png;base64,${part.inlineData.data}`;
            }
        }
    }

    throw new Error("No image generated in the response.");

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export const removeBackground = async (image: ProcessedImage): Promise<string> => {
    const promptText = "Remove the background from the product in the image. The product should be sharp and well-defined, and the background should be completely removed (transparent). Output a PNG image.";

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [
                    { text: promptText },
                    {
                        inlineData: {
                            mimeType: image.mimeType,
                            data: image.base64
                        }
                    }
                ]
            },
            config: {
                responseModalities: ['IMAGE'],
                temperature: 0.4
            }
        });

        const parts = response.candidates?.[0]?.content?.parts;
        if (parts) {
            for (const part of parts) {
                if (part.inlineData && part.inlineData.data) {
                    return `data:image/png;base64,${part.inlineData.data}`;
                }
            }
        }
        throw new Error("Không thể tạo ảnh. Vui lòng thử lại.");
    } catch (error) {
        console.error("Gemini API Error (Remove BG):", error);
        throw error;
    }
};

export const generateAdImage = async (
    productImage: ProcessedImage, 
    logoImage: ProcessedImage | null, 
    customPrompt: string
): Promise<string> => {
    // System prompt directing AI to be a Creative Director
    const systemPrompt = `Bạn là một Giám đốc Sáng tạo AI hàng đầu. Nhiệm vụ của bạn là phân tích ảnh sản phẩm được cung cấp, tự động đề xuất phong cách quảng cáo tốt nhất (ví dụ: tối giản, sang trọng, retro, công nghệ, thân thiện với môi trường) và tạo ra một hình ảnh quảng cáo mới, chất lượng cao, ấn tượng để bán sản phẩm đó.`;

    let logoInstruction = '';
    const parts: any[] = [];

    // Base Prompt
    let baseQuery = `Dựa trên sản phẩm này (ảnh đầu tiên), hãy tạo ra một bức ảnh quảng cáo chuyên nghiệp. Phong cách bổ sung: ${customPrompt}`;

    // Image 1: Product
    parts.push({
        inlineData: {
            mimeType: productImage.mimeType,
            data: productImage.base64
        }
    });

    // Image 2: Logo (Optional)
    if (logoImage) {
        parts.push({
            inlineData: {
                mimeType: logoImage.mimeType,
                data: logoImage.base64
            }
        });
        logoInstruction = 'SỬ DỤNG logo được cung cấp (ảnh thứ hai trong input) và đặt nó ở góc nhỏ, phù hợp nhất của bức ảnh quảng cáo mới. Đảm bảo logo rõ ràng và không che khuất sản phẩm chính.';
    } else {
        logoInstruction = 'Tuyệt đối KHÔNG chèn bất kỳ logo, watermark, hay văn bản nào khác vào bức ảnh quảng cáo. Chỉ tập trung vào hình ảnh sản phẩm và phong cách.';
    }

    const finalQuery = `${baseQuery}. ${logoInstruction}`;

    // Add text prompt as the first part (convention)
    parts.unshift({ text: finalQuery });

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image-preview', // Using the preview model as requested in snippet
            contents: { parts: parts },
            config: {
                systemInstruction: systemPrompt,
                responseModalities: ['IMAGE'],
                temperature: 0.4
            }
        });

        const resultParts = response.candidates?.[0]?.content?.parts;
        if (resultParts) {
            for (const part of resultParts) {
                if (part.inlineData && part.inlineData.data) {
                    return `data:image/png;base64,${part.inlineData.data}`;
                }
            }
        }
        throw new Error("Không nhận được dữ liệu ảnh từ mô hình.");

    } catch (error) {
        console.error("Gemini API Error (Ad Creator):", error);
        throw error;
    }
};

export const generateAdCopy = async (
    productName: string,
    productInfo: string,
    targetAudience: string,
    formula: string,
    formulaDesc: string,
    imageBase64?: { data: string, mimeType: string } | null
): Promise<string> => {
    const promptText = `
        Bạn là một chuyên gia Copywriter hàng đầu tại Việt Nam, chuyên viết content quảng cáo NGẮN GỌN, XÚC TÍCH, và RẤT THUYẾT PHỤC.
        Hãy viết một bài quảng cáo HOÀN CHỈNH cho sản phẩm sau đây, tuân thủ CÔNG THỨC BÁN HÀNG ${formula} (${formulaDesc}):

        - Tên sản phẩm: ${productName}
        - Thông tin sản phẩm: ${productInfo}
        - Đối tượng khách hàng: ${targetAudience || "Đại chúng, những người yêu thích sản phẩm chất lượng cao"}

        ${imageBase64 ? "QUAN TRỌNG: Hãy phân tích hình ảnh đính kèm (màu sắc, bao bì, cảm nhận thị giác, phong cách) để đưa vào bài viết cho sinh động và thuyết phục." : ""}

        YÊU CẦU ĐỊNH DẠNG TUYỆT ĐỐI (Phải tuân thủ 100%):
        1. **NỘI DUNG RA DUY NHẤT:** CHỈ ĐƯA RA MỘT KHỐI VĂN BẢN DUY NHẤT HOÀN CHỈNH (Sẵn sàng để Copy & Paste đăng lên Facebook/Mạng xã hội). KHÔNG BAO GỒM BẤT KỲ PHẦN PHÂN TÍCH, LỜI GIẢI THÍCH, HAY LỰA CHỌN NỘI DUNG NÀO KHÁC.
        2. **ĐỘ DÀI:** Bài viết phải NGẮN GỌN và XÚC TÍCH (tối đa 1500 ký tự). Tập trung vào lợi ích cốt lõi, cảm xúc và thông điệp chính của công thức bán hàng.
        3. **CẤU TRÚC:** Cần có tiêu đề thu hút (dùng IN HOA và Icon), thân bài ngắn gọn theo flow công thức, và Call to Action.
        4. **KHÔNG SỬ DỤNG BẢNG:** Tuyệt đối không tạo Markdown Table hay chia thành các đề mục lớn.
        5. **Phong cách:** Hiện đại, thuyết phục. Sử dụng tiếng Việt tự nhiên, có cảm xúc mạnh.
        6. **Call to Action (CTA):** Đoạn cuối cùng phải có lời kêu gọi mua hàng, thông tin liên hệ và hashtag liên quan.

        Bắt đầu viết content quảng cáo ngay bây giờ:
      `;

    const parts: any[] = [{ text: promptText }];

    if (imageBase64) {
        parts.push({
            inlineData: {
                mimeType: imageBase64.mimeType,
                data: imageBase64.data
            }
        });
    }

    try {
        // Use flash model for text generation with optional image
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash', 
            contents: { parts },
            config: {
                temperature: 0.7,
            }
        });

        return response.text || "Không thể tạo nội dung.";
    } catch (error) {
        console.error("Gemini API Error (Ad Copy):", error);
        throw error;
    }
};

export const generateSpeech = async ({
  text,
  voiceId,
  speed = 1.0,
  pitch = 0,
  isSSML = false
}: {
  text: string;
  voiceId: string;
  speed?: number;
  pitch?: number;
  isSSML?: boolean;
}): Promise<string> => {
    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: {
                parts: [{ text: text }]
            },
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: {
                        prebuiltVoiceConfig: { voiceName: voiceId }
                    }
                }
            }
        });

        const parts = response.candidates?.[0]?.content?.parts;
        if (parts) {
            for (const part of parts) {
                if (part.inlineData && part.inlineData.data) {
                    return part.inlineData.data;
                }
            }
        }
        throw new Error("No audio generated");
    } catch (error) {
        console.error("TTS Error", error);
        throw error;
    }
}

export const decodeAudioData = async (base64String: string, audioContext: AudioContext): Promise<AudioBuffer> => {
  const binaryString = atob(base64String);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  // Gemini 2.5 TTS default sample rate is often 24000Hz.
  // The raw data is PCM 16-bit little-endian mono.
  const sampleRate = 24000;
  const numChannels = 1;

  const dataInt16 = new Int16Array(bytes.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = audioContext.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const audioBufferToWav = (buffer: AudioBuffer): Blob => {
  const numOfChan = buffer.numberOfChannels;
  const length = buffer.length * numOfChan * 2 + 44;
  const bufferArr = new ArrayBuffer(length);
  const view = new DataView(bufferArr);
  const channels = [];
  let i;
  let sample;
  let offset = 0;
  let pos = 0;

  // write WAVE header
  setUint32(0x46464952); // "RIFF"
  setUint32(length - 8); // file length - 8
  setUint32(0x45564157); // "WAVE"

  setUint32(0x20746d66); // "fmt " chunk
  setUint32(16); // length = 16
  setUint16(1); // PCM (uncompressed)
  setUint16(numOfChan);
  setUint32(buffer.sampleRate);
  setUint32(buffer.sampleRate * 2 * numOfChan); // avg. bytes/sec
  setUint16(numOfChan * 2); // block-align
  setUint16(16); // 16-bit (hardcoded in this function)

  setUint32(0x61746164); // "data" - chunk
  setUint32(length - pos - 4); // chunk length

  // write interleaved data
  for(i = 0; i < buffer.numberOfChannels; i++)
    channels.push(buffer.getChannelData(i));

  while(pos < buffer.length) {
    for(i = 0; i < numOfChan; i++) {             // interleave channels
      sample = Math.max(-1, Math.min(1, channels[i][pos])); // clamp
      sample = (0.5 + sample < 0 ? sample * 32768 : sample * 32767)|0; // scale to 16-bit signed int
      view.setInt16(44 + offset, sample, true);          // write 16-bit sample
      offset += 2;
    }
    pos++;
  }

  return new Blob([bufferArr], {type: 'audio/wav'});

  function setUint16(data: any) {
    view.setUint16(pos, data, true);
    pos += 2;
  }

  function setUint32(data: any) {
    view.setUint32(pos, data, true);
    pos += 4;
  }
}

export const generateMarketingImage = async (
  productImg: ProcessedImage,
  faceImg: ProcessedImage | null,
  productName: string,
  feedback: string
): Promise<string> => {

  const parts: any[] = [
    {
      inlineData: {
        data: productImg.base64,
        mimeType: productImg.mimeType
      }
    }
  ];

  if (faceImg) {
    parts.push({
      inlineData: {
        data: faceImg.base64,
        mimeType: faceImg.mimeType
      }
    });
  }

  // Optimized Prompt with Scale Constraints
  let prompt = `Generate a high-quality photorealistic commercial image (Sony A7II style, 85mm f/1.8 lens).

  CORE TASK:
  Synthesize the provided product image and face image (if present) into a cohesive professional marketing photo.

  DETAILS:
  1. PRODUCT: The product '${productName}' must be the focal point, rendered with high fidelity.
  2. SCALE & PROPORTION (CRITICAL): 
     - ANALYZE the product type (e.g., perfume, shampoo, machine) to determine its real-world size.
     - RESIZE the product relative to the model's hands and face. 
     - It MUST NOT be oversized or giant. Maintain realistic physics.
  3. MODEL: Use the provided face for the model. Skin texture must be ultra-realistic.
  4. INTERACTION: The model holds the product naturally. Hand positioning must be physically accurate. Fingers must wrap around the object correctly based on its size.
  5. LIGHTING: Cinematic studio softbox lighting. Soft background bokeh.
  6. COMPOSITION: Vertical (9:16), centered, balanced for social media ads.

  NEGATIVE PROMPT:
  giant product, oversized product, tiny hands, distorted hands, extra fingers, bad anatomy, plastic skin, cartoon, low quality, blurry.

  INSTRUCTION:
  Return ONLY the generated image. Do not provide any text description, introduction, or chatter.
  `;

  if (feedback) {
    prompt += `\nUSER ADJUSTMENTS (IMPORTANT): ${feedback}`;
  }

  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image', // Using image model
      contents: { parts },
      config: {
         imageConfig: {
           aspectRatio: '9:16'
         }
      }
    });

    // Extract image
    if (response.candidates && response.candidates.length > 0) {
      const candidate = response.candidates[0];

      // Check for valid parts
      if (candidate.content && candidate.content.parts) {
        for (const part of candidate.content.parts) {
          if (part.inlineData && part.inlineData.data) {
            return `data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`;
          }
        }
      }

      // If no image, check for text (error explanation from model)
      let textContent = "";
      if (candidate.content && candidate.content.parts) {
         for (const part of candidate.content.parts) {
             if (part.text) textContent += part.text;
         }
      }

      if (candidate.finishReason === 'SAFETY') {
          throw new Error("Hình ảnh bị chặn bởi bộ lọc an toàn (Safety Filter). Hãy thử ảnh hoặc mô tả khác.");
      }

      // If we got text but no image, it implies the model refused or chatted instead of generating.
      if (textContent) {
        console.warn("Model returned text instead of image:", textContent);
        throw new Error("AI không tạo ra hình ảnh mà chỉ trả về văn bản. Vui lòng thử lại hoặc điều chỉnh yêu cầu rõ ràng hơn.");
      }
    }

    throw new Error("Không tìm thấy dữ liệu ảnh trong phản hồi của AI.");
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

