export const generateVirtualTryOn = async (
  modelImg: ImageAsset,
  description: string,
  lighting: string,
  filter: string,
  beautyOptions: string[],
  productImg: ImageAsset | null
): Promise<string> => {

    // Construct Prompt
    let prompt = `ACT AS a professional fashion stylist and digital editor.
    TASK: Virtual Try-On. Change the outfit of the person in the first image.

    TARGET OUTFIT STYLE: ${description}.

    PHOTOGRAPHY SETTINGS:
    - LIGHTING: ${lighting}.
    - FILTER/TONE: ${filter}.
    - BEAUTY ENHANCEMENTS: ${beautyOptions.join(', ')}.

    REQUIREMENTS:
    1. KEEP IDENTITY: The face and identity of the person in Image 1 MUST remain 100% unchanged.
    2. KEEP POSE: The body pose must remain exactly the same.
    3. KEEP BACKGROUND: The background should remain consistent with the original image unless specified otherwise.
    4. OUTFIT FIT: The new outfit must drape naturally over the body, respecting gravity and fabric physics.
    5. QUALITY: High realism, 8k resolution, detailed texture.
    `;

    const parts: any[] = [{ text: prompt }];

    // Image 1: The Model (User)
    parts.push({
        inlineData: {
            mimeType: modelImg.mimeType,
            data: modelImg.base64.split(',')[1] // remove data url prefix if present, assuming utility returned full url
        }
    });

    // Image 2: The Clothing Product (Optional)
    if (productImg) {
        prompt += `\nREFERENCE IMAGE: Use the clothing item in the second image as the EXACT source for the new outfit. Apply it to the person in the first image.`;
        parts[0].text = prompt; // Update text part

        parts.push({
            inlineData: {
                mimeType: productImg.mimeType,
                data: productImg.base64.split(',')[1]
            }
        });
    }

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: { parts },
            config: {
                responseModalities: ['IMAGE'],
                temperature: 0.4
            }
        });

        // Extract image
        const resultParts = response.candidates?.[0]?.content?.parts;
        if (resultParts) {
            for (const part of resultParts) {
                if (part.inlineData && part.inlineData.data) {
                    return `data:image/png;base64,${part.inlineData.data}`;
                }
            }
        }
        throw new Error("Không nhận được hình ảnh từ AI.");
    } catch (error) {
        console.error("Virtual Try-On Error:", error);
        throw error;
    }
};

