export const TextToSpeech: React.FC = () => {
  const [text, setText] = useState("");
  const [language, setLanguage] = useState('vi');
  const [voiceId, setVoiceId] = useState<string>(VOICES_BY_LANGUAGE['vi'].female[0].id);
  const [speed, setSpeed] = useState(1.0);
  const [pitch, setPitch] = useState(0);
  const [isSSML, setIsSSML] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);

  const audioRef = useRef<HTMLAudioElement | null>(null);

  const charCount = text.length;
  const estTokens = useMemo(() => charCount * TOKEN_PER_CHAR, [charCount]);
  const estCost = useMemo(() => (estTokens / 1000) * PRICE_PER_1K_TOKENS, [estTokens]);

  const violations = useMemo(() => {
    const lowerText = text.toLowerCase();
    return BANNED_WORDS.filter(word => lowerText.includes(word));
  }, [text]);

  const selectedVoice = useMemo<Voice>(() => {
    const langVoices = VOICES_BY_LANGUAGE[language];
    const allVoices = [...langVoices.female, ...langVoices.male];
    return allVoices.find((v: any) => v.id === voiceId) || allVoices[0];
  }, [voiceId, language]);

  const createWavBlob = async (base64Audio: string): Promise<Blob> => {
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    try {
        const audioBuffer = await decodeAudioData(base64Audio, ctx);
        const blob = audioBufferToWav(audioBuffer);
        return blob;
    } finally {
        ctx.close();
    }
  };

  const handleSynthesize = useCallback(async () => {
    if (!text.trim()) { setError("Please enter some text to synthesize."); return; }
    if (violations.length > 0) { setError(`Content contains banned words: ${violations.join(", ")}`); return; }
    setError(null); setLoading(true); setAudioUrl(null);
    try {
      const base64Audio = await generateSpeech({ text, voiceId: selectedVoice.apiId, speed: speed, pitch: pitch, isSSML });
      if (!base64Audio) throw new Error("No audio returned");
      const wavBlob = await createWavBlob(base64Audio);
      const url = URL.createObjectURL(wavBlob);
      setAudioUrl(url);
      setTimeout(() => { if (audioRef.current) { audioRef.current.playbackRate = speed; audioRef.current.play().catch(console.error); } }, 100);
    } catch (e: any) {
      console.error(e); setError(e.message || "An error occurred while generating speech.");
    } finally { setLoading(false); }
  }, [text, selectedVoice, speed, pitch, isSSML, violations]);

  const handleDownload = useCallback(() => {
    if (!audioUrl) return;
    const a = document.createElement("a");
    a.href = audioUrl;
    a.download = `tts_${selectedVoice.name.replace(/\s+/g, '_')}_${new Date().toISOString().slice(0,10)}.wav`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
  }, [audioUrl, selectedVoice]);

  const handleLanguageChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const newLang = e.target.value; setLanguage(newLang);
    const newLangVoices = VOICES_BY_LANGUAGE[newLang];
    const firstVoice = newLangVoices.female[0] || newLangVoices.male[0];
    if(firstVoice) { setVoiceId(firstVoice.id); }
  };

  const langVoices = VOICES_BY_LANGUAGE[language];
  const { male: maleVoices, female: femaleVoices } = langVoices;

  return (
    <div className="mx-auto max-w-7xl space-y-4 p-4 font-body h-full overflow-y-auto custom-scrollbar">
      <header className="text-center">
        <h1 className="text-3xl font-display font-bold tracking-tight text-gray-900 sm:text-4xl">AI Voice Studio</h1>
        <p className="mt-2 text-sm text-gray-600">Powered by Google Gemini. Kho giọng đọc đa dạng 3 miền Bắc - Trung - Nam.</p>
      </header>

      <div className="grid grid-cols-1 gap-4 md:grid-cols-3">
        <Card title="Cấu hình" desc="Chọn ngôn ngữ, giọng đọc và tham số">
          <Field>
            <Label htmlFor="lang-select">Ngôn ngữ (Language)</Label>
            <Select id="lang-select" value={language} onChange={handleLanguageChange}>
              <option value="vi">Tiếng Việt</option>
              <option value="en">English</option>
              <option value="zh">中文 (Chinese)</option>
              <option value="es">Español (Spanish)</option>
              <option value="fr">Français (French)</option>
              <option value="de">Deutsch (German)</option>
              <option value="ja">日本語 (Japanese)</option>
              <option value="ko">한국어 (Korean)</option>
              <option value="th">ไทย (Thai)</option>
            </Select>
          </Field>

          <Field>
            <Label htmlFor="voice-select">Giọng đọc (Voice)</Label>
            <Select id="voice-select" value={voiceId} onChange={(e) => setVoiceId(e.target.value)}>
              {femaleVoices.length > 0 && <optgroup label="Giọng Nữ (Female)">{femaleVoices.map((voice: any) => <option key={voice.id} value={voice.id}>{voice.name}</option>)}</optgroup>}
              {maleVoices.length > 0 && <optgroup label="Giọng Nam (Male)">{maleVoices.map((voice: any) => <option key={voice.id} value={voice.id}>{voice.name}</option>)}</optgroup>}
            </Select>
            {selectedVoice && <div className="mt-2 p-2 bg-orange-50 border border-orange-100 rounded text-xs text-orange-800">{selectedVoice.description}</div>}
          </Field>

          <Field>
            <Label htmlFor="speed-range">Tốc độ (Speed): {speed.toFixed(2)}x</Label>
            <input id="speed-range" type="range" min={0.5} max={2} step={0.1} value={speed} onChange={e => setSpeed(parseFloat(e.target.value))} className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer" disabled={isSSML}/>
          </Field>
          <Field>
            <Label htmlFor="pitch-range">Cao độ (Pitch): {pitch} (Mặc định)</Label>
            <input id="pitch-range" type="range" min={-5} max={5} step={1} value={pitch} onChange={e => setPitch(parseFloat(e.target.value))} className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer" disabled={true} title="Tính năng đang cập nhật"/>
          </Field>
          <div className="flex items-center gap-2 mt-4">
            <input id="ssml-checkbox" type="checkbox" checked={isSSML} onChange={e => setIsSSML(e.target.checked)} className="h-4 w-4 rounded border-gray-300 text-orange-600 focus:ring-orange-500"/>
            <label htmlFor="ssml-checkbox" className="text-sm font-medium text-gray-700">Chế độ SSML (Nâng cao)</label>
          </div>
           {isSSML && <p className="mt-1 text-xs text-orange-600">Speed và Pitch sẽ bị vô hiệu hóa trong chế độ SSML.</p>}
        </Card>

        <Card title="Nội dung" desc="Nhập văn bản hoặc SSML">
          <textarea
            className="h-64 w-full resize-none rounded-lg border border-gray-300 p-3 text-sm focus:outline-none focus:ring-2 focus:ring-orange-500 font-mono leading-relaxed"
            placeholder={isSSML ? '<speak>Xin chào <break time="500ms"/> mọi người!</speak>' : "Nhập văn bản cần đọc tại đây..."}
            value={text}
            onChange={(e) => setText(e.target.value)}
          />
          <div className="mt-2 flex items-center justify-between text-xs text-gray-500">
            <span>Ký tự: {charCount.toLocaleString()}</span>
            <span>Ước tính: ~${estCost.toFixed(6)}</span>
          </div>
          {violations.length > 0 && <p className="mt-2 text-xs text-red-600 font-medium">Cảnh báo: Nội dung chứa từ khóa cấm - {violations.join(", ")}</p>}
        </Card>

        <Card title="Kết quả" desc="Nghe thử và tải về">
          <div className="flex flex-col gap-3">
            <Button onClick={handleSynthesize} disabled={loading || !text.trim()} loading={loading} className="w-full py-3">Đọc Ngay (Generate)</Button>
            {error && <div className="p-3 bg-red-50 border border-red-100 rounded text-sm text-red-600">{error}</div>}
            <div className="mt-2 p-4 bg-gray-50 rounded-xl border border-gray-200 flex flex-col items-center justify-center min-h-[120px]">
                {audioUrl ? (
                    <div className="w-full space-y-3">
                        <audio ref={audioRef} src={audioUrl} controls className="w-full" />
